import numpy as np
from scipy.special import factorialk


def my_factorialk(n, k):
    res = factorialk(n, k, exact=True)
    if isinstance(n, np.ndarray):
        res[(n > -k) & (n < 0)] = 1
    else:
        res = 1 if (n > -k) and (n < 0) else res
    return res

def _pmf(self, k, a):
    Pk = 1.0 / special.zeta(a, 1) * (k.astype(float) ** (-a))
    return Pk

from __future__ import annotations

import sys
import tracemalloc

import numpy as np
import scipy
import scipy.sparse as sp

print(scipy.__version__, np.__version__, sys.version_info)
scipy.show_config()


def main():
    for format in ["csr", "csc"]:
        matrices = [
            sp.random_array((10_000, 1000), format=format, rng=np.random.default_rng())
            for _ in range(100)
        ]
        tracemalloc.start()
        print(f"Starting memory for {format}", tracemalloc.get_traced_memory()[0])
        for i in range(100):
            for mat in matrices:
                mat.copy()
            print(
                f"Current memory usage for {format}:",
                tracemalloc.get_traced_memory()[0],
            )
        tracemalloc.stop()


if __name__ == "__main__":
    main()
